import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import {
  getB2bCustomerDetail,
  verifyCustomer,
  setCustomerCredit,
} from "../../features/b2b/b2bSlice";
import {
  ArrowLeft,
  Briefcase,
  ShieldCheck,
  ShieldAlert,
  CreditCard,
  FileText,
  MapPin,
  Calendar,
  MessageSquare,
  DollarSign,
  TrendingUp,
} from "lucide-react";
import { Input, Button, Select, Table, Modal, message, Card } from "antd";

const B2bCustomerDetail = () => {
  const { id } = useParams();
  const dispatch = useDispatch();
  const [creditLimitInput, setCreditLimitInput] = useState("");
  const [paymentTermsInput, setPaymentTermsInput] = useState("PREPAID");
  const [rejectModalOpen, setRejectModalOpen] = useState(false);
  const [rejectReason, setRejectReason] = useState("");

  const { customerDetail, isLoading } = useSelector((state) => state.b2b);

  useEffect(() => {
    dispatch(getB2bCustomerDetail(id));
  }, [dispatch, id]);

  useEffect(() => {
    if (customerDetail) {
      setCreditLimitInput(customerDetail.creditLimit || "0");
      setPaymentTermsInput(customerDetail.paymentTerms || "PREPAID");
    }
  }, [customerDetail]);

  const handleVerify = (action) => {
    if (action === "approve") {
      dispatch(verifyCustomer({ id, action: "approve" })).then((res) => {
        if (res.meta.requestStatus === "fulfilled") {
          message.success("Account verified successfully.");
        } else {
          message.error("Failed to verify customer.");
        }
      });
    } else {
      setRejectModalOpen(true);
    }
  };

  const submitReject = () => {
    dispatch(verifyCustomer({ id, action: "reject", reason: rejectReason })).then(
      (res) => {
        if (res.meta.requestStatus === "fulfilled") {
          message.warning("Account verification rejected.");
          setRejectModalOpen(false);
          setRejectReason("");
        } else {
          message.error("Failed to reject verification.");
        }
      }
    );
  };

  const handleUpdateCredit = () => {
    dispatch(
      setCustomerCredit({
        id,
        creditLimit: parseFloat(creditLimitInput) || 0,
        paymentTerms: paymentTermsInput,
      })
    ).then((res) => {
      if (res.meta.requestStatus === "fulfilled") {
        message.success("Credit terms updated successfully.");
      } else {
        message.error("Failed to update credit terms.");
      }
    });
  };

  const orderColumns = [
    {
      title: "Order ID",
      dataIndex: "id",
      render: (id) => (
        <Link
          to={`/admin/b2b/orders/${id}`}
          className="font-mono text-[11px] font-black text-blue-600 bg-blue-50 px-2 py-1 rounded-lg border border-blue-100 uppercase"
        >
          #{id.slice(-6)}
        </Link>
      ),
    },
    {
      title: "Type",
      dataIndex: "orderType",
      render: (type) => (
        <span className="font-bold text-slate-700 text-xs tracking-wider uppercase">
          {type}
        </span>
      ),
    },
    {
      title: "Procurement Status",
      dataIndex: "procurementStatus",
      render: (status) => (
        <div
          className={`status-badge ${
            status === "DELIVERED"
              ? "success"
              : status === "CANCELLED"
              ? "danger"
              : "info"
          }`}
        >
          <div
            className={`w-1.5 h-1.5 rounded-full ${
              status === "DELIVERED"
                ? "bg-emerald-500"
                : status === "CANCELLED"
                ? "bg-rose-500"
                : "bg-blue-500"
            }`}
          />
          {status || "PENDING"}
        </div>
      ),
    },
    {
      title: "Amount",
      dataIndex: "totalPrice",
      render: (val) => (
        <span className="font-black text-slate-800">
          {parseFloat(val).toLocaleString()}{" "}
          <span className="text-[10px] text-slate-400">ETB</span>
        </span>
      ),
    },
    {
      title: "Order Date",
      dataIndex: "createdAt",
      render: (date) => (
        <span className="text-slate-500 font-medium text-xs">
          {new Date(date).toLocaleDateString()}
        </span>
      ),
    },
  ];

  if (isLoading || !customerDetail) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] opacity-50">
        <div className="w-8 h-8 rounded-full border-2 border-blue-600 border-t-transparent animate-spin mb-4" />
        <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
          Retrieving Profile...
        </p>
      </div>
    );
  }

  // Load documents safely
  const docs = customerDetail.verificationDocuments || {};
  const docList = Object.entries(docs).map(([name, url]) => ({
    name: name.replace(/([A-Z])/g, " $1"),
    url,
  }));

  return (
    <div className="space-y-8 pb-12">
      {/* Back Header */}
      <div className="flex items-center gap-4">
        <Link
          to="/admin/b2b/customers"
          className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-colors shadow-sm"
        >
          <ArrowLeft size={18} className="text-slate-500" />
        </Link>
        <div>
          <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em]">
            B2B Client Detail
          </span>
          <h1 className="text-[28px] font-bold text-slate-900 tracking-tight leading-tight">
            {customerDetail.institutionName || "Institution Profile"}
          </h1>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Profile Details & Verification Actions */}
        <div className="lg:col-span-2 space-y-8">
          {/* Card 1: Main Info */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex justify-between items-start flex-wrap gap-4 mb-8">
              <div className="flex items-center gap-4">
                <div className="w-16 h-16 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center font-bold text-2xl border border-blue-100/50">
                  {customerDetail.institutionName?.charAt(0) || "I"}
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900 leading-tight">
                    {customerDetail.institutionName}
                  </h2>
                  <span className="px-3 py-1 rounded-lg bg-slate-50 border border-slate-100 text-[10px] font-black text-slate-500 inline-block mt-1 uppercase tracking-wider">
                    {customerDetail.customerType?.replace(/_/g, " ")}
                  </span>
                </div>
              </div>
              <div>
                {customerDetail.isVerified ? (
                  <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-2xl text-[12px] font-black">
                    <ShieldCheck size={18} />
                    VERIFIED PARTNER
                  </div>
                ) : (
                  <div className="flex items-center gap-2 px-4 py-2 bg-amber-50 text-amber-600 border border-amber-100 rounded-2xl text-[12px] font-black">
                    <ShieldAlert size={18} className="animate-pulse" />
                    PENDING VERIFICATION
                  </div>
                )}
              </div>
            </div>

            {/* General Info Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 border-t border-slate-50 pt-8">
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">
                  Contact Person
                </p>
                <p className="font-bold text-slate-800 text-[15px]">
                  {customerDetail.contactPersonName || "Not Provided"}
                </p>
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">
                  Contact Phone
                </p>
                <p className="font-bold text-slate-800 text-[15px]">
                  {customerDetail.contactPersonPhone || "Not Provided"}
                </p>
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">
                  Business License #
                </p>
                <p className="font-bold text-slate-800 text-[15px]">
                  {customerDetail.businessLicenseNumber || "Not Provided"}
                </p>
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">
                  Tax Identification Number (TIN)
                </p>
                <p className="font-bold text-slate-800 text-[15px]">
                  {customerDetail.taxIdentificationNumber || "Not Provided"}
                </p>
              </div>
            </div>

            {/* Verification Actions for pending accounts */}
            {!customerDetail.isVerified && (
              <div className="mt-8 p-6 bg-slate-50 rounded-2xl border border-slate-100 flex flex-col sm:flex-row justify-between items-center gap-4">
                <div>
                  <h4 className="font-bold text-slate-800 text-sm">
                    Verify this wholesale account
                  </h4>
                  <p className="text-slate-500 text-xs font-medium mt-0.5">
                    Before approving, verify that the license and TIN uploads match local records.
                  </p>
                </div>
                <div className="flex gap-3 w-full sm:w-auto">
                  <Button
                    danger
                    className="rounded-xl font-bold h-10 px-6 sm:w-auto flex-1 border border-slate-200"
                    onClick={() => handleVerify("reject")}
                  >
                    Reject
                  </Button>
                  <Button
                    type="primary"
                    className="bg-blue-600 hover:bg-blue-700 rounded-xl font-bold h-10 px-6 sm:w-auto flex-1"
                    onClick={() => handleVerify("approve")}
                  >
                    Approve / Verify
                  </Button>
                </div>
              </div>
            )}
          </div>

          {/* Card 2: Saved Delivery Locations */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <MapPin size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">
                Registered Shipping Addresses
              </h3>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {customerDetail.addresses?.length > 0 ? (
                customerDetail.addresses.map((addr) => (
                  <div
                    key={addr.id}
                    className={`p-5 rounded-2xl border ${
                      addr.isDefault
                        ? "border-blue-100 bg-blue-50/20"
                        : "border-slate-100"
                    }`}
                  >
                    <div className="flex justify-between items-center mb-2">
                      <span className="font-black text-xs uppercase tracking-wider text-slate-400">
                        {addr.label || "Address"}
                      </span>
                      {addr.isDefault && (
                        <span className="text-[10px] font-black bg-blue-100 text-blue-600 px-2 py-0.5 rounded-md">
                          DEFAULT
                        </span>
                      )}
                    </div>
                    <p className="font-bold text-slate-800 text-[14px]">
                      {addr.recipientName}
                    </p>
                    <p className="text-slate-500 text-[13px] font-medium mt-1">
                      {addr.line1}
                      {addr.line2 ? `, ${addr.line2}` : ""}, {addr.city},{" "}
                      {addr.region}, {addr.country}
                    </p>
                    <p className="text-slate-400 text-xs mt-2 font-medium">
                      Phone: {addr.phone}
                    </p>
                  </div>
                ))
              ) : (
                <div className="sm:col-span-2 text-center py-6 text-slate-400 font-bold text-sm">
                  No addresses registered.
                </div>
              )}
            </div>
          </div>

          {/* Card 3: Purchase History */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <Calendar size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">
                Order Activity History
              </h3>
            </div>
            <Table
              columns={orderColumns}
              dataSource={customerDetail.orders || []}
              pagination={{ pageSize: 5 }}
              className="modern-table"
              rowKey="id"
            />
          </div>
        </div>

        {/* Sidebar Controls (Credit limits, documents) */}
        <div className="space-y-8">
          {/* Card 4: Financial KPIs */}
          <div className="bg-gradient-to-br from-slate-900 to-slate-800 text-white rounded-3xl p-8 shadow-xl relative overflow-hidden group">
            <div className="relative z-10">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                Procurement Spend
              </span>
              <h3 className="text-3xl font-black mt-2 tracking-tight">
                {parseFloat(customerDetail.lifetimeSpend || 0).toLocaleString()}
                <span className="text-xs text-slate-400 font-bold uppercase ml-2">
                  ETB
                </span>
              </h3>
              <p className="text-slate-400 text-sm font-bold mt-4">
                Total Orders Fulfilled:{" "}
                <span className="text-white">{customerDetail.totalOrders || 0}</span>
              </p>
            </div>
            <div className="absolute right-4 bottom-4 text-white/5 group-hover:scale-110 transition-transform duration-500">
              <DollarSign size={100} />
            </div>
          </div>

          {/* Card 5: Credit Limit Adjustments */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <CreditCard size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">Credit Control</h3>
            </div>
            <div className="space-y-5">
              <div>
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                  Payment Terms
                </label>
                <Select
                  value={paymentTermsInput}
                  onChange={(val) => setPaymentTermsInput(val)}
                  className="w-full h-11"
                >
                  <Select.Option value="PREPAID">PREPAID</Select.Option>
                  <Select.Option value="NET_30">NET 30</Select.Option>
                  <Select.Option value="NET_60">NET 60</Select.Option>
                  <Select.Option value="NET_90">NET 90</Select.Option>
                </Select>
              </div>

              <div>
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                  Credit Limit (ETB)
                </label>
                <Input
                  type="number"
                  value={creditLimitInput}
                  onChange={(e) => setCreditLimitInput(e.target.value)}
                  className="h-11 rounded-xl font-bold"
                  placeholder="0"
                />
              </div>

              <Button
                type="primary"
                onClick={handleUpdateCredit}
                className="bg-blue-600 hover:bg-blue-700 h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full"
              >
                Apply Terms
              </Button>
            </div>
          </div>

          {/* Card 6: Uploaded Documents */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <FileText size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">
                Verification Documents
              </h3>
            </div>
            <div className="space-y-3">
              {docList.length > 0 ? (
                docList.map((doc, idx) => (
                  <a
                    key={idx}
                    href={doc.url}
                    target="_blank"
                    rel="noreferrer"
                    className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-blue-50/50 hover:border-blue-100 transition-all group"
                  >
                    <span className="font-bold text-slate-800 text-[13px] capitalize group-hover:text-blue-600">
                      {doc.name}
                    </span>
                    <FileText size={16} className="text-slate-400 group-hover:text-blue-500" />
                  </a>
                ))
              ) : (
                <div className="text-center py-6 text-slate-400 font-bold text-sm">
                  No documents uploaded.
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Reject Verification Modal */}
      <Modal
        title="Reject B2B Application"
        open={rejectModalOpen}
        onCancel={() => setRejectModalOpen(false)}
        onOk={submitReject}
        okText="Confirm Rejection"
        okButtonProps={{ danger: true, className: "rounded-xl font-bold h-10" }}
        cancelButtonProps={{ className: "rounded-xl font-bold h-10" }}
        centered
      >
        <div className="space-y-4 py-4">
          <p className="text-slate-500 font-medium text-[13px]">
            Please enter a reason for rejecting this B2B profile application. This reason will be logged and visible to the client.
          </p>
          <Input.TextArea
            value={rejectReason}
            onChange={(e) => setRejectReason(e.target.value)}
            rows={4}
            className="rounded-xl font-medium"
            placeholder="e.g. Invalid business license uploaded or business name mismatch..."
          />
        </div>
      </Modal>
    </div>
  );
};

export default B2bCustomerDetail;
